// Input: items = [{ json: { node, vmid, name, type, status, cpu, mem, maxmem, data: {...} } }, ...]
// Output: items = [{ json: { node, vmid, hostname, type, status, cpu_pct, ram:{used, total, pct, used_h, total_h}, interfaces:[{name, ip, gw, bridge}] } }, ...]

function toBytesStr(n) {
  if (n == null) return '';
  const units = ['B','KB','MB','GB','TB','PB'];
  let i = 0; let v = Number(n);
  while (v >= 1024 && i < units.length - 1) { v /= 1024; i++; }
  return `${v.toFixed(2)} ${units[i]}`;
}
function pct(used, total) {
  if (!total) return 0;
  return Number(((Number(used) / Number(total)) * 100).toFixed(1));
}
function parseKVString(s) {
  const out = {};
  if (!s || typeof s !== 'string') return out;
  for (const part of s.split(',')) {
    const idx = part.indexOf('=');
    if (idx === -1) continue;
    const k = part.slice(0, idx).trim();
    const v = part.slice(idx + 1).trim();
    out[k] = v;
  }
  return out;
}

return items.map(it => {
  const r = it.json || {};
  const d = r.data || {};

  // RAM
  const memUsed = Number(r.mem || 0);
  const memTotal = Number(r.maxmem || 0);

  // Interfaces: net0..netX
  const interfaces = [];
  Object.entries(d)
    .filter(([k]) => k.startsWith('net'))
    .sort(([a], [b]) => a.localeCompare(b))
    .forEach(([k, val]) => {
      const n = parseKVString(val);
      interfaces.push({
        name: n.name || k,                                   // eth0/ens18…
        ip: (n.ip || '').split('/')[0] || null,              // 10.x.x.x
        gw: n.gw || null,                                    // 10.x.x.1
        bridge: n.bridge || null,                            // vmbr2…
      });
    });

  const out = {
    node: r.node || '',
    vmid: r.vmid,
    hostname: d.hostname || r.name || '',
    type: r.type || 'lxc',
    status: r.status || '',
    cpu_pct: Number(((r.cpu || 0) * 100).toFixed(2)),
    ram: {
      used: memUsed,
      total: memTotal,
      pct: pct(memUsed, memTotal),
      used_h: toBytesStr(memUsed),
      total_h: toBytesStr(memTotal),
    },
    interfaces,
  };

  return { json: out };
});

// Input: items = [{ json: { node, vmid, hostname, type, status, cpu_pct, ram:{used_h,total_h,pct}, interfaces:[{name,ip,gw,bridge}]} }, ...]
// Output: [{ json: { markdown: "..." } }]

function fmtCPU(x) {
  const n = Number(x || 0);
  return `${n.toFixed(2)}%`;
}
function fmtRAM(ram) {
  if (!ram) return '—';
  const u = ram.used_h || '—';
  const t = ram.total_h || '—';
  const p = (ram.pct != null) ? `${Number(ram.pct).toFixed(1)}%` : '—';
  return `${u} / ${t} (${p})`;
}
function fmtStatus(s) {
  // Petit badge visuel
  if (s === 'running') return '🟢 running';
  if (s === 'stopped') return '⚪ stopped';
  return s || '—';
}
function fmtInterfaces(list) {
  if (!Array.isArray(list) || list.length === 0) return '—';
  // Une ligne par interface ; <br> marche dans BookStack
  return list.map(n => {
    const name = n.name || 'iface';
    const ip = n.ip || '—';
    const gw = n.gw || '—';
    const br = n.bridge || '—';
    // ex: eth0: x.x.x.x (gw x.x.x.1) [vmbr2]
    return `${name}: ${ip} (gw ${gw}) [${br}]`;
  }).join('<br>');
}

// Groupement par node
const byNode = {};
for (const it of items) {
  const o = it.json || {};
  const node = o.node || 'unknown';
  if (!byNode[node]) byNode[node] = [];
  byNode[node].push(o);
}

// Tri: running d'abord, puis hostname
for (const node of Object.keys(byNode)) {
  byNode[node].sort((a, b) => {
    const sa = a.status === 'running' ? 0 : 1;
    const sb = b.status === 'running' ? 0 : 1;
    if (sa !== sb) return sa - sb;
    const ha = (a.hostname || '').toLowerCase();
    const hb = (b.hostname || '').toLowerCase();
    if (ha < hb) return -1;
    if (ha > hb) return 1;
    return (a.vmid || 0) - (b.vmid || 0);
  });
}

// Construction Markdown
const now = new Date().toISOString().replace('T', ' ').replace(/\.\d+Z$/, ' UTC');
let md = `# Inventaire LXC — Proxmox\n\n_MAJ: ${now}_\n\n`;

for (const node of Object.keys(byNode).sort()) {
  const arr = byNode[node];
  md += `## Nœud: \`${node}\` (${arr.length} LXC)\n\n`;
  md += `| VMID | Hostname | Type | Status | CPU | RAM | Interfaces |\n`;
  md += `|-----:|---------:|:-----|:-------|----:|:----|:-----------|\n`;

  for (const o of arr) {
    const vmid = o.vmid ?? '—';
    const host = o.hostname || '—';
    const type = o.type || '—';
    const status = fmtStatus(o.status);
    const cpu = fmtCPU(o.cpu_pct);
    const ram = fmtRAM(o.ram);
    const ifs = fmtInterfaces(o.interfaces);

    // Attention aux pipes dans les cellules — ici on n’en a pas
    md += `| ${vmid} | ${host} | ${type} | ${status} | ${cpu} | ${ram} | ${ifs} |\n`;
  }

  md += `\n`;
}

// Optionnel : on prépare un emplacement pour la liste incrémentielle d’IPs.
// Si tu fais le merge plus tard, tu remplacerais/compléterais ce commentaire.
md += `<!-- KNOWN_IPS:[] -->\n`;

return [{ json: { markdown: md } }];

const items = $json.data || [];
const qemu = items.filter(vm => vm.type === 'qemu' && vm.status === 'running');
return qemu.map(vm => ({
  json: {
    node: vm.node,
    vmid: vm.vmid,
    name: vm.name
  }
}));

const items = $json.data || [];
const qemu = items.filter(vm => vm.type === 'qemu' && vm.status === 'running');
return qemu.map(vm => ({
  json: {
    node: vm.node,
    vmid: vm.vmid,
    name: vm.name
  }
}));

// Code node
// Mode: Run Once for All Items

// Récupère tous les items de Merge QEMU Nodes (node/vmid/name)
const merge2Items = $items('Merge QEMU Nodes', 0); // runIndex 0
// Récupère tous les items de Merge QEMU Config And Network (GA network-get-interfaces)
const merge1Items = $items('Merge QEMU Config And Network', 0); // runIndex 0

const out = [];

// petite fonction utilitaire pour filtrer les IPv4 valides
function isValidIPv4(ip) {
  if (!ip) return false;
  if (ip === '127.0.0.1') return false;          // loopback
  if (ip.startsWith('169.254.')) return false;   // APIPA
  return true;
}

for (let i = 0; i < merge2Items.length; i++) {
  const ctx = merge2Items[i]?.json || {};
  const ga  = merge1Items[i]?.json || {};

  const node = ctx.node || null;
  const vmid = ctx.vmid || null;
  const hostname = ctx.name || null;

  const result = (ga.data && ga.data.result) || [];
  const interfaces = [];

  for (const iface of result) {
    const ifName = iface.name || '';
    const macRaw = iface['hardware-address'] || '';
    const mac = macRaw.toLowerCase();

    // skip MAC nulles
    if (!mac || mac === '00:00:00:00:00:00') continue;

    const ipAddrs = iface['ip-addresses'] || [];
    const ipv4s = ipAddrs
      .filter(ip => ip['ip-address-type'] === 'ipv4')
      .map(ip => ip['ip-address'])
      .filter(isValidIPv4);

    for (const ip of ipv4s) {
      interfaces.push({
        name: ifName,
        mac,
        ip,
      });
    }
  }

  out.push({
    json: {
      node,
      vmid,
      hostname,
      interfaces,
    },
  });
}

return out;

// Node: QEMU → Markdown (simple)
// Mode: Run Once for All Items

// On récupère toutes les VMs
const vms = items.map(i => i.json);

// Optionnel : trier par node puis VMID si tu veux un ordre stable
vms.sort((a, b) => {
  if ((a.node || "") < (b.node || "")) return -1;
  if ((a.node || "") > (b.node || "")) return 1;
  return (a.vmid || 0) - (b.vmid || 0);
});

// Fonction pour formater les interfaces d'une VM
function formatInterfaces(vm) {
  if (!vm.interfaces || vm.interfaces.length === 0) {
    return "";
  }

  // Tri des interfaces dans l'ordre net0, net1, net2,...
  const list = [...vm.interfaces].sort((a, b) =>
    (a.name || "").localeCompare(b.name || "", undefined, { numeric: true })
  );

  return list
    .map(intf => {
      const ip = intf.ip || "";
      const bridge = intf.bridge ? ` [${intf.bridge}]` : "";
      return `${intf.name}: ${ip}${bridge}`;
    })
    .join("<br>");
}

// Construction du markdown
let md = `# Inventaire IP — VMs QEMU\n\n_MAJ: ${new Date().toISOString()}_\n\n`;

md += `| VMID | Hostname | Interfaces |\n`;
md += `|-----:|----------|:-----------|\n`;

for (const vm of vms) {
  const vmid = vm.vmid ?? "—";
  const hostname = vm.hostname ?? vm.name ?? "—";
  const interfaces = formatInterfaces(vm);

  md += `| ${vmid} | ${hostname} | ${interfaces} |\n`;
}

md += `\n<!-- KNOWN_IPS:[] -->\n`;

return [
  {
    json: {
      markdown: md,
    },
  },
];

// Code node "Dedup VMs"
// Mode: Run Once for All Items

const seen = new Set();
const out = [];

for (const item of items) {
  const j = item.json || {};

  // On fabrique une clé unique par VM
  const node = j.node || j.nodename || '';
  const vmid = j.vmid != null ? String(j.vmid) : '';
  const hostname = j.hostname || j.name || '';

  const key = `${node}|${vmid}|${hostname}`;

  if (seen.has(key)) {
    // VM déjà vue -> on la zappe
    continue;
  }

  seen.add(key);
  out.push(item);
}

return out;
